import{_ as e,o as l,c as r,a2 as t}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"F06: 存貨與債務穩定度審計 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6261_久元/20260512/F06_存貨與債務穩定度審計.md","filePath":"審計報告庫/財務審計/6261_久元/20260512/F06_存貨與債務穩定度審計.md"}'),i={name:"審計報告庫/財務審計/6261_久元/20260512/F06_存貨與債務穩定度審計.md"};function o(h,a,n,s,d,c){return l(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="f06-存貨與債務穩定度審計-財務審計專家報告" tabindex="-1">F06: 存貨與債務穩定度審計 - 財務審計專家報告 <a class="header-anchor" href="#f06-存貨與債務穩定度審計-財務審計專家報告" aria-label="Permalink to &quot;F06: 存貨與債務穩定度審計 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>存貨與債務的穩定度如何？是否存在存貨積壓或過高的債務壓力？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：存貨2024暴增39%後2025去化15%，DIO 520天仍高。債務風險極低—短借僅0.14億無長借，現金14.2億充分覆蓋。存貨品質是唯一風險點</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：截至2025年合併資產負債表</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>：存貨9.90→13.76→11.69億。DIO 728→520天(改善但仍高)。CCC 423→514→479天。負債率17.6%無長借短借僅0.14億。現金14.2億。ICR 15.5倍。存貨效率為同業最差水準(京元68天)，但債務風險極低。現金3年-46%從26.4降至14.2億為隱憂。</li><li><strong>診斷見解</strong>：債務健康度為最強一環但存貨效率為結構性弱點，資金大量積壓於庫存與AR環節壓縮投資靈活性，雙重佔用營運資金降低整體資產回報率。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="存貨風險" tabindex="-1">存貨風險 <a class="header-anchor" href="#存貨風險" aria-label="Permalink to &quot;存貨風險&quot;">​</a></h3><p>DIO 728→520天改善但仍遠高同業京元68天。原物料+在製品2024暴增為因，2025各類全面縮減。跌價損失減半至1,716萬。營運資金效率結構性低落，若2026訂單波動需再提跌價。</p><h3 id="債務" tabindex="-1">債務 <a class="header-anchor" href="#債務" aria-label="Permalink to &quot;債務&quot;">​</a></h3><p>短借0.14億(利率0.70-1.29%)、長借已清、負債率17.6%、ICR 15.5倍。利息支出極低，無償債壓力。現金14.2億較高點減46%，為CapEx擴張後暫時現象，銀行授信取得容易。</p><h3 id="營運週期" tabindex="-1">營運週期 <a class="header-anchor" href="#營運週期" aria-label="Permalink to &quot;營運週期&quot;">​</a></h3><p>CCC 423→514→479天，投產至收款間隔約15個月。DPO異常300天已回歸155天，但DSO增28天抵銷降存貨效益。最大制約在DIO 520天，資金大量積壓於庫存環節影響週轉效率。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><h3 id="🔴-空方觀點" tabindex="-1">🔴 空方觀點 <a class="header-anchor" href="#🔴-空方觀點" aria-label="Permalink to &quot;🔴 空方觀點&quot;">​</a></h3><ol><li>DIO 520天為同業最差水準(京元68天)，營運資金大量積壓庫存壓縮投資靈活性，存貨效率低落為利空因素</li><li>現金從26.4→14.2億(-46%)，若CapEx續高2027年恐跌破10億，流動性緊縮風險上升</li><li>原料4.38億(37%)vs製成品5.46億(47%)，若訂單無法消化將轉呆滯庫存，存貨跌價損失居高不下為潛在隱憂</li></ol><h3 id="🟢-多方觀點" tabindex="-1">🟢 多方觀點 <a class="header-anchor" href="#🟢-多方觀點" aria-label="Permalink to &quot;🟢 多方觀點&quot;">​</a></h3><ol><li>去庫存方向明確，2025各類全面縮減跌價損失減半</li><li>無實質借款、流動比358%、ICR 15.5倍，償債能力最強一環</li><li>過去曾有長借1.42億額度，零借款狀態提供極大財務彈性</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>債務風險極低但存貨效率為結構性弱點。已見改善但不徹底。真正的風險在資金使用效率—過多資金鎖在庫存與AR無法用於生產性投資。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：財務分析工具.py(inventory_check 6261 2023 2025)</li><li>數據查詢日期：2026-05-12</li></ul>',23)])])}const b=e(i,[["render",o]]);export{_ as __pageData,b as default};
